const j = $input.first().json;
const raw = (j.content && j.content[0] && j.content[0].text) ? j.content[0].text : (typeof j.text === 'string' ? j.text : '');
let parsed;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch[0]);
} catch(e) {
  parsed = {
    classification: 'ROUTINE',
    priority_score: 5,
    sender_type: 'Unknown',
    summary: 'Could not parse — review manually',
    suggested_action: 'Review manually',
    draft_reply: '',
    requires_michael: true
  };
}
return [{ json: { ...parsed, original_from: $('Gmail Trigger — Unread Emails').first().json.from, original_subject: $('Gmail Trigger — Unread Emails').first().json.subject, email_id: $('Gmail Trigger — Unread Emails').first().json.id, timestamp: new Date().toISOString() } }];
